export const useWebSocketStore = defineStore('websocket', () => {
  // ... 现有代码 ...

  // 处理不同类型的 WebSocket 消息
  function handleMessage(event: MessageEvent) {
    try {
      const message = JSON.parse(event.data)

      switch (message.type) {
        case 'iteration.status_changed':
          // 更新迭代状态
          iterationStore.updateIteration(message.data)
          break

        case 'agent.status_changed':
          // 更新 Agent 状态
          agentStore.updateAgent(message.data)
          break

        case 'system.metrics':
          // 更新系统指标
          overviewStore.updateMetrics(message.data)
          break

        case 'log.entry':
          // 添加日志条目
          logStore.addLog(message.data)
          break

        case 'iteration.progress':
          // 更新迭代进度
          iterationStore.updateProgress(message.data)
          break

        default:
          console.warn('Unknown WebSocket message type:', message.type)
      }
    } catch (error) {
      console.error('Failed to parse WebSocket message:', error)
    }
  }

  return {
    // ... 现有返回值 ...
    handleMessage
  }
})
```

#### 2.2 完善 Agent Store 实时更新

```typescript
// stores/agent.ts
export const useAgentStore = defineStore('agent', () => {
  const agents = ref<Agent[]>([])
  const loading = ref(false)

  // 初始化 10 个 Agent
  function initAgents() {
    agents.value = [
      {
        id: 'product-manager',
        name: '产品经理',
        status: 'idle',
        icon: 'document',
        color: '#409eff',
        tasksCompleted: 0,
        avgExecutionTime: 0,
        lastExecution: null
      },
      {
        id: 'architect',
        name: '架构师',
        status: 'idle',
        icon: 'office-building',
        color: '#67c23a',
        tasksCompleted: 0,
        avgExecutionTime: 0,
        lastExecution: null
      },
      // ... 其他 8 个 Agent
    ]
  }

  // 更新 Agent 状态
  function updateAgent(data: Partial<Agent> & { id: string }) {
    const agent = agents.value.find(a => a.id === data.id)
    if (agent) {
      Object.assign(agent, data)
    }
  }

  // 更新 Agent 进度
  function updateAgentProgress(agentId: string, progress: number) {
    const agent = agents.value.find(a => a.id === agentId)
    if (agent) {
      agent.progress = progress
    }
  }

  return {
    agents,
    loading,
    initAgents,
    updateAgent,
    updateAgentProgress
  }
})
```

